(self.webpackChunkblog_vuepress=self.webpackChunkblog_vuepress||[]).push([[672],{3966:(n,l,s)=>{"use strict";s.r(l),s.d(l,{data:()=>e});const e={key:"v-1676ebf2",path:"/technology/%E6%B1%87%E7%BC%96%E5%A4%8D%E4%B9%A0%E7%AC%94%E8%AE%B0.html",title:"汇编复习笔记",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"第一章",slug:"第一章",children:[]},{level:2,title:"第二章",slug:"第二章",children:[{level:3,title:"硬件和软件",slug:"硬件和软件",children:[]},{level:3,title:"中央处理器",slug:"中央处理器",children:[]},{level:3,title:"外部设备",slug:"外部设备",children:[]}]},{level:2,title:"第三章",slug:"第三章",children:[{level:3,title:"寻址方式",slug:"寻址方式",children:[]},{level:3,title:"数据传送指令",slug:"数据传送指令",children:[]},{level:3,title:"循环",slug:"循环",children:[]},{level:3,title:"子程序",slug:"子程序",children:[]},{level:3,title:"中断",slug:"中断",children:[]}]},{level:2,title:"第四章",slug:"第四章",children:[{level:3,title:"伪操作",slug:"伪操作",children:[]}]}],filePathRelative:"technology/汇编复习笔记.md",git:{updatedTime:1626432089e3}}},8780:(n,l,s)=>{"use strict";s.r(l),s.d(l,{default:()=>a});const e=(0,s(6252).uE)('<h1 id="汇编复习笔记" tabindex="-1"><a class="header-anchor" href="#汇编复习笔记" aria-hidden="true">#</a> 汇编复习笔记</h1><h2 id="第一章" tabindex="-1"><a class="header-anchor" href="#第一章" aria-hidden="true">#</a> 第一章</h2><ul><li>进制相互之间转换</li><li>同进制运算</li><li>正反补码</li><li>补码运算</li><li>无符号整数</li><li>字符表示法（ASCII）</li><li>逻辑运算</li></ul><h2 id="第二章" tabindex="-1"><a class="header-anchor" href="#第二章" aria-hidden="true">#</a> 第二章</h2><h3 id="硬件和软件" tabindex="-1"><a class="header-anchor" href="#硬件和软件" aria-hidden="true">#</a> 硬件和软件</h3><h3 id="中央处理器" tabindex="-1"><a class="header-anchor" href="#中央处理器" aria-hidden="true">#</a> 中央处理器</h3><p><strong>寄存器</strong></p><blockquote><p>通用寄存器</p></blockquote><ul><li>AX（Accumulator，累加）</li><li>BX（Base，基址）</li><li>CX（Count，计数）</li><li>DX（Data，数据） <ul><li>以上四个可以 16 位访问，也可以 8 位访问</li></ul></li></ul><hr><ul><li>BP（Base Pointer，基址指针）</li><li>SI（Source Index，源变址）</li><li>DI（Destination Index，目的变址） <ul><li>以上三个只能以 16 位访问</li></ul></li></ul><blockquote><p>专用寄存器</p></blockquote><ul><li>IP（Instruction Pointer，指令指针）</li><li>SP（Stack Pointer，堆栈指针）</li><li>FLAGS / PSW（Program Status Word，程序状态） <ul><li><p>OF（Overflow Flag，溢出标志）</p></li><li><p>SF（Sign Flag，符号标志）</p></li><li><p>ZF（Zero Flag，零位标志）</p></li><li><p>CF（Carry Flag，进位标志）</p><hr></li><li><p>AF（Auxiliary Carry Flag，辅助进位标志）</p></li><li><p>PF（Parity Flag，奇偶标志）</p></li><li><p>DF（Direction Flag，方向标志）</p></li><li><p>TF（Trap Flag，陷阱标志）</p></li><li><p>IF（Interrupt Flag，中断标志）</p></li></ul></li></ul><blockquote><p>段寄存器</p></blockquote><ul><li>CS（Code Segment，代码段）</li><li>DS（Data Segment，数据段）</li><li>SS（Stack Segment，堆栈段）</li><li>ES（Extra Segment，附加段）</li></ul><p><strong>存储器</strong></p><p>存储器的无穷大空间数组，可以通过字节，字和双字等不同形式访问。</p><p>最大寻址范围取决于地址总线长度。</p><h3 id="外部设备" tabindex="-1"><a class="header-anchor" href="#外部设备" aria-hidden="true">#</a> 外部设备</h3><h2 id="第三章" tabindex="-1"><a class="header-anchor" href="#第三章" aria-hidden="true">#</a> 第三章</h2><h3 id="寻址方式" tabindex="-1"><a class="header-anchor" href="#寻址方式" aria-hidden="true">#</a> 寻址方式</h3><div class="language-assembly ext-assembly line-numbers-mode"><pre class="language-assembly"><code>; 立即寻址（Immediate Addressing）：使用的是立即数，所以叫立即寻址\nMOV AL, 5\n\n; 寄存器寻址（Register Addressing）：使用的是寄存器，所以叫寄存器寻址\nMOV AX, BX\n\n; 直接寻址（Direct Addressing）：直接到相应地址上找数据，所以叫直接寻址\n; 需要加上 DS 里面的内容\nMOV AX, [2000H]\n\n; 寄存器间接寻址（Register Indirect Addressing）\nMOV AX, [BX]\n\n; 寄存器相对寻址 / 直接变址寻址（Register Relative Addressing）\nMOV AX, COUNT[SI]\nMOV AX, [COUNT+SI]\n\n; 基址变址寻址（Based Indexed Addressing）\nMOV AX, [BX][DI]\nMOV AX, [BX+DI]\n\n; 相对基址变址寻址（Relative Based Indexed Addressing）\nMOV AX, MASK[BX][SI]\nMOV AX, MASK[BX+SI]\nMOV AX, [MASK+BX+SI]\n\n; 比例变址寻址（Scaled Indexed Addressing）\nMOV EAX, COUNT[ESI*4]\n\n; 基址比例变址寻址（Based Scaled Indexed Addressing）\nMOV EAX, [EAX],[EDX*8]\n\n; 相对基址比例变址寻址（Relative Based Scaled Indexed Addressing）\nMOV EAX, TABLE[EBP][EDI*4]\n\n\n\n; 段内直接寻址（Intrasegment Direct Addressing）\n; PROGIA 和 QUEST 均为转向的符号地址\n; 如果位移量为 16 位，则在符号地址前加操作符 NEAR PTR\n; 如果位移量为 8 位，则在符号地址前加操作符 SHORT\nJMP NEAR PTR PROGIA\nJMP SHORT QUEST\n\n; 段内间接寻址（Intrasegment Indirect Addressing）\nJMP BX\nJMP WORD PTR[BP+TABLE]\nJMP TABLE[BX]\nJMP [BX][SI]\nJMP ECX\n\n; 段间直接寻址（Intersegment Direct Addressing）\nJMP FAR PTR NEXTROUTINT\n\n; 段间间接寻址（Intersegment Indirect Addressing）\nJMP DWORD PTR[INTERS+BX]\nJMP DWORD PTR [EDI]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br></div></div><h3 id="数据传送指令" tabindex="-1"><a class="header-anchor" href="#数据传送指令" aria-hidden="true">#</a> 数据传送指令</h3><ul><li><p>通用数据传送指令</p><ul><li>MOV</li><li>PUSH</li><li>POP</li><li>PUSHA / PUSHAD</li><li>POPA / POPAD</li></ul><div class="language-assembly ext-assembly line-numbers-mode"><pre class="language-assembly"><code>MOV AX, DATA_SEGMENT\nMOV DS, AX\n\nMOV AL, &#39;E&#39;\n\nMOV BX, OFFSET TABLE\n\n; PUSH 和 POP 的指针和数据存储的先后顺序\nPUSH SRC\n\nPOP DST\n\nPUSHA\n\nPOPAD\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div></li><li><p>地址传送指令</p><ul><li>LEA</li></ul><div class="language-assembly ext-assembly line-numbers-mode"><pre class="language-assembly"><code>LEA REG, SRC\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div></li><li><p>算术指令</p><ul><li>ADD</li><li>INC</li><li>SUB</li><li>DEC</li><li>NEG</li><li>CMP</li><li>MUL</li><li>DIV</li></ul><div class="language-assembly ext-assembly line-numbers-mode"><pre class="language-assembly"><code>; (DST) + (SRC) --&gt; (DST)\nADD DST, SRC\n\n; (OPR) + 1 --&gt; (OPR)\nINC OPR\n\n; (DST) - (SRC) --&gt; (DST)\nSUB DST, SRC\n\n; (OPR) - 1 --&gt; (OPR)\nDEC OPR\n\n; (OPR) --&gt; (OPR)\n; 作用是求补码\nNEG OPR\n\n; 比较指令\n; 跟 SUB 执行一样的操作，但是不保存结果\n; 只保存 FLAGS\nCMP OPR1, OPR2\n\n; 注意：\n; 目的操作数只能为 AX / AL\n; 结果存放在 AX / DX+AX / EDX+EAX 中\n; 其中 (E)AX 存低位，(E)DX 存高位\nMUL SRC\n\n; 注意：\n; 16 位被除数在 AX 中，8 位除数为源操作数。8 位商存在 AL 中，8 位余数在 AH 中\n; 32 位被除数在 DX,AX 中，其中 DX 为高位字。16 位除数为源操作数，16 位商存在 AX 中，16 位余数在 DX 中\n; 64 位被除数在 EDX,EAX 中，其中 EDX 为高位双字。32 位除数为源操作数，32 位商存在 EAX 中，32 位余数在 EDX 中\nDIV SRC\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br></div></div></li><li><p>逻辑运算指令</p><ul><li>AND</li><li>OR</li><li>NOT</li><li>XOR</li><li>TEST</li></ul></li><li><p>移位指令</p><ul><li><p>SHL：逻辑左移</p></li><li><p>SAL：算术左移</p></li><li><p>SHR：逻辑右移</p></li><li><p>SAR：算术右移</p></li><li><p>ROL：循环左移</p></li><li><p>ROR：循环右移</p><ul><li><p>通用用法：OPTION OPR, CNT</p></li><li><p>注意：</p><blockquote><ol><li>OPTION 为上述移位指令中的任何一个；</li><li>OPR 用除了立即数以外的任何寻址方式；</li><li>移位次数由 CNT 决定，可以是 1 - 31。但是如果需要移位的次数大于 1，需要将其存在 CL 寄存器中，移位指令中的 CNT 直接写为 CL 即可。如果为 1，啧不受此限制</li></ol></blockquote></li></ul></li></ul></li><li><p>串处理指令</p><ul><li><p>MOVS：串传送</p></li><li><p>CMPS：串比较</p></li><li><p>SCAS：串扫描</p></li><li><p>LODS：从串取</p></li><li><p>STOS：存入串</p></li><li><p>INS：串输入</p></li><li><p>OUTS：串输出</p><hr><p>与上述基本指令配合使用的前缀：</p><hr></li><li><p>REP：重复</p></li><li><p>REPE / REPZ：相等 / 为零则重复</p></li><li><p>REPNE / REPNZ：不相等 / 不为零则重复</p></li></ul></li><li><p>控制转移指令</p><ul><li><p>JMP</p><ul><li>段内直接短转移：<code>JMP SHORT OPR</code></li><li>段内直接近转移：<code>JMP NEAR PTR OPR</code></li><li>段内间接近转移：<code>JMP WORD PTR OPR</code></li><li>段间直接远转移：<code>JMP FAR PTR OPR</code></li><li>段间间接远转移：<code>JMP DWORD PTR OPR</code></li></ul></li><li><p>JE / JZ</p></li><li><p>JNE / JNZ</p></li><li><p>JS / JNS</p></li><li><p>JO / JNO</p><hr></li><li><p>比较无符号数：（B: Below, E：Equal, A：Above, C：Carry, N：Not）</p><ul><li>JB / JNAE / JC</li><li>JNB / JAE / JNC</li><li>JBE / JNA</li><li>JA / JNBE</li></ul><hr></li><li><p>比较有符号数：（G: Greater, E：Equal, L：Less, C：Carry, N：Not）</p><ul><li>JL / JNGE</li><li>JNL / JGE</li><li>JLE / JNG</li><li>JG / JNLE</li></ul></li></ul></li></ul><h3 id="循环" tabindex="-1"><a class="header-anchor" href="#循环" aria-hidden="true">#</a> 循环</h3><h3 id="子程序" tabindex="-1"><a class="header-anchor" href="#子程序" aria-hidden="true">#</a> 子程序</h3><ul><li>CALL</li><li>RET</li></ul><h3 id="中断" tabindex="-1"><a class="header-anchor" href="#中断" aria-hidden="true">#</a> 中断</h3><h2 id="第四章" tabindex="-1"><a class="header-anchor" href="#第四章" aria-hidden="true">#</a> 第四章</h2><h3 id="伪操作" tabindex="-1"><a class="header-anchor" href="#伪操作" aria-hidden="true">#</a> 伪操作</h3><ul><li>地址计数器 <strong>$</strong>： <ul><li>用在指令中时，表示本条指令的第一个字节的地址。</li><li>在指令中用到 $ 时，它只代表该指令的首地址，而与 $ 本身所在的字节无关。</li><li>用在伪操作的参数字段时，表示的是地址计数器的当前值。</li></ul></li><li>ORG： <ul><li>用来设置当前计数器的值。</li></ul></li></ul>',31),a={render:function(n,l){return e}}}}]);